import{c as a,S as i,j as t,m as s}from"./chunks/framework.CHVLliLb.js";const c=JSON.parse('{"title":"Replicating and expanding the Imperial 2026 DRC Bundibugyo outbreak analysis with joint Bayesian modelling","description":"","frontmatter":{},"headers":[],"relativePath":"index.md","filePath":"index.md","lastUpdated":null}'),n={name:"index.md"};function r(o,e,l,p,h,d){return i(),t("div",null,[...e[0]||(e[0]=[s(`<h1 id="Replicating-and-expanding-the-Imperial-2026-DRC-Bundibugyo-outbreak-analysis-with-joint-Bayesian-modelling" tabindex="-1">Replicating and expanding the Imperial 2026 DRC Bundibugyo outbreak analysis with joint Bayesian modelling <a class="header-anchor" href="#Replicating-and-expanding-the-Imperial-2026-DRC-Bundibugyo-outbreak-analysis-with-joint-Bayesian-modelling" aria-label="Permalink to &quot;Replicating and expanding the Imperial 2026 DRC Bundibugyo outbreak analysis with joint Bayesian modelling {#Replicating-and-expanding-the-Imperial-2026-DRC-Bundibugyo-outbreak-analysis-with-joint-Bayesian-modelling}&quot;">​</a></h1><p>Joint generative Turing model for the 2026 Bundibugyo virus disease outbreak in DRC, fitting the data streams from the Imperial / WHO report (McCabe et al., <a href="https://doi.org/10.25560/130007" target="_blank" rel="noreferrer">18 May 2026</a>) in a single posterior.</p><p><strong>Data last updated:</strong> 19 May 2026 (sources per <a href="https://github.com/epiforecasts/BVDOutbreakSize/blob/main/data/observations.toml" target="_blank" rel="noreferrer"><code>data/observations.toml</code></a>).</p><p>The original report runs two independent analyses — geographic spread from cases detected in Uganda, and backcalculation from deaths — and reports a sensitivity sweep over fixed nuisance parameters. Here those nuisance parameters carry priors, all streams are conditioned on jointly, and the output is one posterior over cumulative cases <code>C_T</code>.</p><p>What it does differently: replaces Imperial&#39;s sensitivity sweep over fixed nuisance parameters with priors, replaces the closed-form deaths approximation with the full gamma convolution, replaces the small-growth-rate exports simplification with the exact cumulative integral, and adds a reported-case ascertainment extension and a no-onward-transmission projected-deaths counterfactual. The <a href="https://epiforecasts.github.io/BVDOutbreakSize/analysis/" target="_blank" rel="noreferrer">analysis walkthrough</a> lays out each deviation alongside the matching Imperial method.</p><h2 id="Running" tabindex="-1">Running <a class="header-anchor" href="#Running" aria-label="Permalink to &quot;Running {#Running}&quot;">​</a></h2><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> clone</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --recurse-submodules</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> https://github.com/seabbs/BVDOutbreakSize</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">cd</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> BVDOutbreakSize</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">julia</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --project=.</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -e</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;using Pkg; Pkg.instantiate()&#39;</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">julia</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --project=.</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> docs/examples/analysis.jl</span></span></code></pre></div><p>Render the docs page (executes the literate and produces HTML at <code>docs/build/</code>):</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">julia</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --project=docs</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -e</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;using Pkg; Pkg.develop(PackageSpec(path=pwd())); Pkg.instantiate()&#39;</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">julia</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --project=docs</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> docs/make.jl</span></span></code></pre></div><p>Updating the observation counts for a new sitrep is a single-file edit of <code>data/observations.toml</code>; the literate picks the new numbers up automatically.</p><h2 id="Submodules" tabindex="-1">Submodules <a class="header-anchor" href="#Submodules" aria-label="Permalink to &quot;Submodules {#Submodules}&quot;">​</a></h2><ul><li><code>external/bdbv-linelist-analysis</code> — Bayesian reanalysis of the 2012 Isiro BDBV line list (Rosello et al. 2015). Source of the informative onset-to-death gamma shape and scale priors.</li></ul><h2 id="Citation" tabindex="-1">Citation <a class="header-anchor" href="#Citation" aria-label="Permalink to &quot;Citation {#Citation}&quot;">​</a></h2><p>If you use or build on this project, please cite the three works this repository depends on:</p><ul><li><p><strong>This project</strong> — Abbott, S. (2026). <em>BVDOutbreakSize: joint forward-generative Turing model for the 2026 DRC Bundibugyo outbreak.</em> <a href="https://github.com/epiforecasts/BVDOutbreakSize" target="_blank" rel="noreferrer">https://github.com/epiforecasts/BVDOutbreakSize</a>.</p></li><li><p><strong>Imperial / WHO report</strong> that this work re-implements — McCabe, R., Ebbarnezh, L., Okware, S., Fotsing, R., Koua, E., Mbaka, P., Lofungola, A., van Elsland, S. L., McMenamin, M., Ferguson, N., le Polain de Waroux, O., Cori, A. (2026). <em>Estimation of the size of the outbreak of Ebola disease caused by Bundibugyo virus in DRC.</em> Imperial College London, 18 May 2026. DOI: <a href="https://doi.org/10.25560/130007" target="_blank" rel="noreferrer">10.25560/130007</a>.</p></li><li><p><strong>Onset-to-death delay reanalysis</strong> that this work uses for delay priors — Funk, S. (2026). <em>bdbv-linelist-analysis: Bayesian reanalysis of the 2012 Isiro Bundibugyo line list.</em> <a href="https://github.com/sbfnk/bdbv-linelist-analysis" target="_blank" rel="noreferrer">https://github.com/sbfnk/bdbv-linelist-analysis</a>.</p></li></ul><h2 id="Further-references" tabindex="-1">Further references <a class="header-anchor" href="#Further-references" aria-label="Permalink to &quot;Further references {#Further-references}&quot;">​</a></h2><ul><li><p>Rosello et al., <em>Ebola virus disease in DRC, 1976–2014</em>, eLife</p><ol><li>Original Isiro 2012 onset-to-death gamma point estimate.</li></ol></li><li><p>Imai et al., <em>Estimating the potential total number of novel coronavirus cases in Wuhan City</em>, Imperial COVID-19 Response Team Report 1, 17 January 2020. Methodological template for Method 1.</p></li><li><p>Charniga et al., <em>Best practices for estimating and reporting epidemiological delay distributions</em>, PLOS Computational Biology</p><ol><li>Followed for the delay-distribution reporting here.</li></ol></li></ul>`,17)])])}const g=a(n,[["render",r]]);export{c as __pageData,g as default};
